module parallel_load_register(
   input                clk,
   input                rst_n,
   input                en,
   input      [32-1:1-1]    D,

   output reg [31:0]    Q
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) Q <= 32'd0;
        else if (en) Q <= D;
    end
endmodule
